import * as React from "react"
import { cn } from "@/lib/utils"

export interface InputProps
  extends React.InputHTMLAttributes<HTMLInputElement> {}

const Input = React.forwardRef<HTMLInputElement, InputProps>(
  ({ className, type, ...props }, ref) => {
    return (
      <input
        type={type}
        className={cn(
          "flex h-9 w-full rounded-md border border-input bg-background px-3 py-1 text-sm shadow-sm transition-colors file:border-0 file:bg-transparent file:text-sm file:font-medium placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50",
          className
        )}
        ref={ref}
        {...props}
      />
    )
  }
)
Input.displayName = "Input"

export { Input }

// We do not import Database globally because it relies on Tauri IPC which crashes standard web browsers
// import Database from '@tauri-apps/plugin-sql';

let dbInstance: any = null;

export async function getDb(): Promise<any> {
  if (!dbInstance) {
    if (window.__TAURI_INTERNALS__) {
      const { default: Database } = await import('@tauri-apps/plugin-sql');
      dbInstance = await Database.load('sqlite:data.db');
    }
  }
  return dbInstance;
}

export interface Order {
  id?: number;
  order_id: string;
  customer_name: string;
  phone: string;
  product: string;
  quantity: number;
  price: number;
  created_at?: string;
}

export async function createOrder(order: Order): Promise<void> {
  const db = await getDb();
  await db.execute(
    `INSERT INTO orders (order_id, customer_name, phone, product, quantity, price) 
     VALUES ($1, $2, $3, $4, $5, $6)`,
    [
      order.order_id,
      order.customer_name,
      order.phone,
      order.product,
      order.quantity,
      order.price,
    ]
  );
}

export async function getOrders(searchQuery: string = ""): Promise<Order[]> {
  const db = await getDb();
  if (searchQuery) {
    return await db.select<Order[]>(
      `SELECT * FROM orders WHERE phone LIKE $1 ORDER BY created_at DESC`,
      [`%${searchQuery}%`]
    );
  }
  return await db.select<Order[]>(`SELECT * FROM orders ORDER BY created_at DESC`);
}

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import type { Order } from "./db";

export function generateInvoicePDF(order: Order) {
  // Create a new PDF document
  const doc = new jsPDF();

  // Set default font
  doc.setFont("helvetica");

  // Title / Header
  doc.setFontSize(22);
  doc.setTextColor(40, 40, 40);
  doc.text("INVOICE", 14, 20);

  // Company Info (Placeholder)
  doc.setFontSize(10);
  doc.setTextColor(100, 100, 100);
  doc.text("Smart Order & Invoice Toolkit", 14, 28);
  doc.text("123 Business Road, Tech City", 14, 33);
  doc.text("support@smarttoolkit.com", 14, 38);

  // Invoice Details
  const rightColX = 140;
  doc.setFontSize(10);
  doc.setTextColor(40, 40, 40);
  doc.text(`Invoice # ${order.order_id}`, rightColX, 28);
  const dateStr = order.created_at ? new Date(order.created_at).toLocaleDateString() : new Date().toLocaleDateString();
  doc.text(`Date: ${dateStr}`, rightColX, 33);

  // Bill To Section
  doc.setFontSize(12);
  doc.setTextColor(40, 40, 40);
  doc.text("Bill To:", 14, 52);

  doc.setFontSize(10);
  doc.setTextColor(80, 80, 80);
  doc.text(order.customer_name, 14, 58);
  if (order.phone) {
    doc.text(`Phone: ${order.phone}`, 14, 63);
  }

  // Draw Line
  doc.setDrawColor(200, 200, 200);
  doc.line(14, 70, 196, 70);

  // Order Items Table
  const totalAmount = order.quantity * order.price;

  autoTable(doc, {
    startY: 75,
    head: [["Description", "Quantity", "Unit Price", "Total"]],
    body: [
      [order.product, order.quantity.toString(), `$${order.price.toFixed(2)}`, `$${totalAmount.toFixed(2)}`],
    ],
    theme: "striped",
    headStyles: {
      fillColor: [31, 41, 55], // text-slate-800
      textColor: [255, 255, 255],
    },
    styles: {
      fontSize: 10,
    },
    columnStyles: {
      0: { cellWidth: 80 },
      1: { halign: "center" },
      2: { halign: "right" },
      3: { halign: "right" },
    },
  });

  // Calculate final Y position after table
  const finalY = (doc as any).lastAutoTable.finalY || 100;

  // Add Summary / Total
  doc.setFontSize(12);
  doc.setTextColor(40, 40, 40);
  doc.text("Total Due:", 140, finalY + 15);
  doc.setFontSize(14);
  doc.setTextColor(31, 41, 55); // Primary dark color
  doc.text(`$${totalAmount.toFixed(2)}`, 165, finalY + 15, { align: "left" });

  // Add footer
  doc.setFontSize(9);
  doc.setTextColor(150, 150, 150);
  doc.text("Thank you for your business!", 105, 280, { align: "center" });

  // Save the PDF
  doc.save(`Invoice_${order.order_id}.pdf`);
}

